// ── Helpers ────────────────────────────────────────────────────────────────
function fmt(d) { return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); }
function today() { return fmt(new Date()); }
function parseDate(s) { const [y,m,d]=s.split('-'); return new Date(y,m-1,d); }
function fmtDisp(s) { 
  const d = parseDate(s);
  return d.toLocaleDateString('de-CH',{weekday:'long',day:'numeric',month:'long'}); 
}
function fmtDispShort(s) { 
  const d = parseDate(s);
  return d.toLocaleDateString('de-CH',{day:'numeric',month:'short'}); 
}
function calcDuration(start, end) {
  if (!start||!end) return '';
  const [sh,sm]=start.split(':').map(Number);
  const [eh,em]=end.split(':').map(Number);
  const mins = (eh*60+em)-(sh*60+sm);
  if (mins<=0) return '';
  if (mins<60) return `${mins} Min.`;
  const h=Math.floor(mins/60), m=mins%60;
  return m>0 ? `${h}h ${m}m` : `${h}h`;
}

function showToast(msg) {
  const t = document.getElementById('toast');
  if (!t) { console.warn('Toast not found, msg:', msg); return; }
  t.textContent = String(msg);
  t.classList.add('show');
  clearTimeout(t._timer);
  t._timer = setTimeout(()=>t.classList.remove('show'), 2800);
}

function uid() { return currentUser?.uid; }
function userRef(col) { return collection(db, 'users', uid(), col); }

// ── Settings Persistence ───────────────────────────────────────────────────
function loadSettings() {
  // Load from localStorage first (instant, no flash)
  isDark = localStorage.getItem('pp_dark') === '1';
  colorTheme = localStorage.getItem('pp_color') || 'blue';
  applyTheme();
}
async function loadSettingsFromFirestore() {
  if (!uid()) return;
  try {
    const snap = await getDoc(doc(db, 'users', uid()));
    if (!snap.exists()) return;
    const data = snap.data();
    if (data.settings) {
      const s = data.settings;
      if (s.dark !== undefined) { isDark = s.dark; localStorage.setItem('pp_dark', isDark?'1':'0'); }
      if (s.color) { colorTheme = s.color; localStorage.setItem('pp_color', colorTheme); }
      if (s.geminiKey) { localStorage.setItem('pp_gemini_key', s.geminiKey); }
      applyTheme();
    }
  } catch(e) { console.warn('Settings load error:', e); }
}
async function saveSettingsToFirestore() {
  if (!uid()) return;
  try {
    await updateDoc(doc(db, 'users', uid()), {
      settings: {
        dark: isDark,
        color: colorTheme,
        geminiKey: localStorage.getItem('pp_gemini_key') || ''
      }
    });
  } catch(e) { console.warn('Settings save error:', e); }
}
function applyTheme() {
  const body = document.body;
  body.classList.toggle('dark', isDark);
  body.classList.remove('violet','orange');
  if (colorTheme !== 'blue') body.classList.add(colorTheme);
  const dt = document.getElementById('dark-toggle');
  if (dt) dt.classList.toggle('on', isDark);
  updateHomeLogo();
  ['blue','violet','orange'].forEach(c=>{
    const el=document.getElementById('color-'+c);
    if(el) el.classList.toggle('active',c===colorTheme);
  });
}
window.toggleDark = function() {
  isDark = !isDark;
  localStorage.setItem('pp_dark', isDark?'1':'0');
  applyTheme();
  saveSettingsToFirestore();
};
window.setColor = function(c) {
  colorTheme = c;
  localStorage.setItem('pp_color', c);
  applyTheme();
  saveSettingsToFirestore();
};

// ── Auth ───────────────────────────────────────────────────────────────────
window.switchAuth = function(tab) {
  document.getElementById('auth-login').classList.toggle('hidden', tab!=='login');
  document.getElementById('auth-register').classList.toggle('hidden', tab!=='register');
  document.querySelectorAll('.auth-tab').forEach((t,i)=>t.classList.toggle('active',(i===0&&tab==='login')||(i===1&&tab==='register')));
};
window.doLogin = async function() {
  const email=document.getElementById('login-email').value;
  const pw=document.getElementById('login-pw').value;
  document.getElementById('login-err').textContent='';
  try { await signInWithEmailAndPassword(auth,email,pw); }
  catch(e){ document.getElementById('login-err').textContent=authErrMsg(e.code); }
};
window.doRegister = async function() {
  const name=document.getElementById('reg-name').value.trim();
  const email=document.getElementById('reg-email').value;
  const pw=document.getElementById('reg-pw').value;
  document.getElementById('reg-err').textContent='';
  if (!name) { document.getElementById('reg-err').textContent='Bitte Namen eingeben.'; return; }
  try {
    const cred = await createUserWithEmailAndPassword(auth,email,pw);
    await updateProfile(cred.user,{displayName:name});
    await setDoc(doc(db,'users',cred.user.uid),{name,email,createdAt:new Date().toISOString()});
  } catch(e){ document.getElementById('reg-err').textContent=authErrMsg(e.code); }
};
window.doLogout = async function() {
  await signOut(auth);
};

