window.confirmDeleteAccount = async function() {
  const pw = document.getElementById('del-acc-pw').value;
  const err = document.getElementById('del-acc-err');
  if (!pw) { err.textContent = 'Bitte Passwort eingeben.'; return; }

  const btn = document.querySelector('#delete-account-modal .btn-primary, #delete-account-modal button[onclick="confirmDeleteAccount()"]');

  try {
    // Re-authenticate first (required by Firebase before delete)
    const credential = EmailAuthProvider.credential(currentUser.email, pw);
    await reauthenticateWithCredential(currentUser, credential);

    // Delete all Firestore data
    err.textContent = '';
    const delCol = async (col) => {
      const snap = await getDocs(userRef(col));
      await Promise.all(snap.docs.map(d => deleteDoc(d.ref)));
    };
    await Promise.all([delCol('plans'), delCol('events'), delCol('subjects')]);
    await deleteDoc(doc(db, 'users', uid()));

    // Delete auth account
    await deleteUser(currentUser);
    document.getElementById('delete-account-modal')?.remove();
    showToast('Konto gelöscht.');
  } catch(e) {
    console.error(e);
    if (e.code === 'auth/wrong-password' || e.code === 'auth/invalid-credential') {
      err.textContent = 'Falsches Passwort.';
    } else {
      err.textContent = 'Fehler: ' + (e.message || e.code);
    }
  }
};
function authErrMsg(code) {
  const m = {'auth/user-not-found':'Kein Konto gefunden.','auth/wrong-password':'Falsches Passwort.','auth/invalid-email':'Ungültige E-Mail.','auth/email-already-in-use':'E-Mail bereits verwendet.','auth/weak-password':'Passwort zu schwach (min. 6 Zeichen).','auth/invalid-credential':'E-Mail oder Passwort falsch.'};
  return m[code]||'Fehler. Bitte erneut versuchen.';
}

// ── Data Loading ───────────────────────────────────────────────────────────
async function loadAll() {
  const [plansSnap, eventsSnap, subjectsSnap, semestersSnap] = await Promise.all([
    getDocs(userRef('plans')),
    getDocs(userRef('events')),
    getDocs(userRef('subjects')),
    getDocs(userRef('semesters'))
  ]);
  plans = {};
  plansSnap.forEach(d=>{ plans[d.id]={...d.data(),id:d.id}; });
  events = [];
  eventsSnap.forEach(d=>{ events.push({...d.data(),id:d.id}); });
  events.sort((a,b)=>a.date.localeCompare(b.date));
  subjects = [];
  subjectsSnap.forEach(d=>{ subjects.push({id:d.id,...d.data()}); });
  semesters = [];
  semestersSnap.forEach(d=>{ semesters.push({id:d.id,...d.data()}); });
  semesters.sort((a,b) => (a.createdAt||'').localeCompare(b.createdAt||''));
  if(semesters.length === 0) {
    try {
      const ref = await addDoc(userRef('semesters'), {name:'Semester 1', isCurrent:true, createdAt:new Date().toISOString()});
      semesters.push({id:ref.id, name:'Semester 1', isCurrent:true});
    } catch(e) {
      semesters.push({id:'local-1', name:'Semester 1', isCurrent:true});
    }
  }
  const cur = semesters.find(s=>s.isCurrent) || semesters[0];
  currentSemesterId = cur ? cur.id : 'local-1';
}

// ── Tab Switching ──────────────────────────────────────────────────────────
window.switchTab = function(tab) {
  currentTab = tab;
  ['home','plan','cal','learn','settings'].forEach(t=>{
    document.getElementById('tab-'+t).classList.toggle('hidden',t!==tab);
    document.getElementById('nav-'+t)?.classList.toggle('active',t===tab);
  });
  // Always scroll to top when switching tabs
  const ca = document.getElementById('content-area');
  if(ca) ca.scrollTop = 0;
  // Home pill: dim when not active
  const pill = document.querySelector('.nav-home-pill');
  if(pill) pill.style.opacity = tab==='home' ? '1' : '0.65';
  if(tab==='home') renderHome();
  if(tab==='plan') { planningDay = new Date(); renderPlan(); }
  if(tab==='cal') renderCal();
  if(tab==='learn') renderLearn();
  if(tab==='settings') renderSettings();
};

// ── HOME TAB ──────────────────────────────────────────────────────────────
function renderHome() {
  const todayStr = today();
  const d = new Date();
  document.getElementById('home-date').textContent = d.toLocaleDateString('de-CH',{weekday:'long',day:'numeric',month:'long',year:'numeric'});
  const plan = plans[todayStr];
  const container = document.getElementById('home-tasks');
  container.innerHTML = '';
  if(!plan||!plan.tasks||plan.tasks.length===0){
    container.innerHTML=`<div class="empty-state"><svg viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/><line x1="8" y1="14" x2="16" y2="14"/><line x1="8" y1="18" x2="12" y2="18"/></svg><h3>Kein Tagesplan</h3><p>Gehe zur Planung, um den heutigen Tag zu planen.</p></div>`;
    document.getElementById('home-progress-wrap').style.display='none';
    document.getElementById('home-progress-txt').textContent='';
    return;
  }
  document.getElementById('home-progress-wrap').style.display='block';
  let total=0,done=0;
  plan.tasks.forEach(t=>{
    if(t.subtasks&&t.subtasks.length>0){t.subtasks.forEach(s=>{total++;if(s.done)done++;});}
    else{total++;if(t.done)done++;}
  });
  const pct = total>0?Math.round(done/total*100):0;
  document.getElementById('home-progress-bar').style.width=pct+'%';
  document.getElementById('home-progress-txt').textContent=`${done} von ${total} Aufgaben erledigt`;
  plan.tasks.forEach((task,ti)=>{
    if(task.done&&(!task.subtasks||task.subtasks.every(s=>s.done))) return;
    const el = document.createElement('div');
    el.className='plan-item';
    const hasSubs = task.subtasks&&task.subtasks.length>0;
    const allSubsDone = hasSubs&&task.subtasks.every(s=>s.done);
    const dur = calcDuration(task.startTime,task.endTime);
    el.innerHTML=`
      <div class="plan-item-header" onclick="toggleTaskExpand(this)">
        <div class="plan-check ${task.done?'done':''}" id="chk-${ti}" ${!hasSubs?`onclick="checkTask(event,'${todayStr}',${ti})"`:''}>
          <svg viewBox="0 0 24 24"><polyline points="20 6 9 12 4 9"/></svg>
        </div>
        <div class="plan-title ${task.done?'completed-txt':''}">${task.title}</div>
        <div class="plan-time">${task.startTime||''} ${task.endTime?'– '+task.endTime:''}<br><span class="plan-duration">${dur}</span></div>
      </div>
      ${hasSubs?`<div class="plan-subtasks" id="subs-${ti}">
        ${task.subtasks.map((s,si)=>{
          if(s.done) return '';
          const sd=calcDuration(s.startTime,s.endTime);
          return `<div class="plan-subtask" id="subtask-${ti}-${si}">
            <div class="plan-sub-check ${s.done?'done':''}" onclick="checkSubtask(event,'${todayStr}',${ti},${si})">
              <svg viewBox="0 0 24 24"><polyline points="20 6 9 12 4 9"/></svg>
            </div>
            <div class="plan-sub-title ${s.done?'completed-txt':''}">${s.title}</div>
            <div class="plan-sub-time">${s.startTime||''} ${s.endTime?'– '+s.endTime:''}<br><span class="plan-sub-dur">${sd}</span></div>
          </div>`;
        }).join('')}
      </div>`:''}
    `;
    container.appendChild(el);
  });
  if(container.innerHTML===''){
    container.innerHTML=`<div class="empty-state"><svg viewBox="0 0 24 24"><polyline points="20 6 9 12 4 9"/></svg><h3>Alles erledigt! 🎉</h3><p>Grossartige Arbeit heute!</p></div>`;
  }
}
window.toggleTaskExpand = function(el) {};
window.checkTask = async function(e, dateStr, ti) {
  e.stopPropagation();
  if(!plans[dateStr]) return;
  plans[dateStr].tasks[ti].done = true;
  await setDoc(doc(db,'users',uid(),'plans',dateStr), plans[dateStr]);
  showToast('Aufgabe erledigt ✓');
  renderHome();
};
window.checkSubtask = async function(e, dateStr, ti, si) {
  e.stopPropagation();
  if(!plans[dateStr]) return;
  plans[dateStr].tasks[ti].subtasks[si].done = true;
  const allDone = plans[dateStr].tasks[ti].subtasks.every(s=>s.done);
  if(allDone) plans[dateStr].tasks[ti].done = true;
  await setDoc(doc(db,'users',uid(),'plans',dateStr), plans[dateStr]);
  showToast('Teilaufgabe erledigt ✓');
  renderHome();
};

// ── PLANNING TAB ──────────────────────────────────────────────────────────
function renderPlan() {
  const dateStr = fmt(planningDay);
  const isToday = dateStr===today();
  const label = document.getElementById('day-nav-label');
  label.textContent = fmtDisp(dateStr);

  // Events for this day
  const dayEvents = events.filter(e => e.date === dateStr);
  const evSec = document.getElementById('plan-events-section');
  if (evSec) {
    if (dayEvents.length > 0) {
      evSec.innerHTML = `<div style="font-size:12px;font-weight:800;color:var(--warn);text-transform:uppercase;letter-spacing:.5px;padding:10px 16px 4px;">📅 Ereignisse</div>
        <div class="plan-event-list">${dayEvents.map(ev => `
          <div class="plan-event-item">
            <div class="plan-event-dot"></div>
            <div class="plan-event-title">${ev.title}</div>
            ${ev.time ? `<div class="plan-event-time">${ev.time}</div>` : ''}
          </div>`).join('')}
        </div>`;
    } else {
      evSec.innerHTML = '';
    }
  }

  const cont = document.getElementById('plan-day-content');
  cont.innerHTML='';
  const plan = plans[dateStr];
  if(!plan||!plan.tasks||plan.tasks.length===0){
    cont.innerHTML=`<div class="empty-state"><svg viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg><h3>Kein Plan für diesen Tag</h3><p>Erstelle einen Tagesplan!</p></div>`;
    return;
  }
  plan.tasks.forEach((task,ti)=>{
    const dur=calcDuration(task.startTime,task.endTime);
    const card=document.createElement('div');
    card.className='plan-day-card';
    const hasSubs=task.subtasks&&task.subtasks.length>0;
    card.innerHTML=`
      <div class="plan-day-header" onclick="this.nextElementSibling.classList.toggle('hidden')">
        <div>
          <div class="plan-day-title">${task.title}</div>
          <div class="plan-day-meta">${task.startTime||''}${task.endTime?' – '+task.endTime:''} ${dur?'· '+dur:''}</div>
        </div>
        <svg viewBox="0 0 24 24" style="width:18px;stroke:var(--txt2);stroke-width:2;fill:none;"><polyline points="6 9 12 15 18 9"/></svg>
      </div>
      <div class="plan-day-body hidden">
        ${hasSubs?task.subtasks.map(s=>{
          const sd=calcDuration(s.startTime,s.endTime);
          return `<div class="plan-day-item"><div class="plan-day-dot sub"></div><div class="plan-day-text">${s.title}</div><div class="plan-day-time-txt">${s.startTime||''}${s.endTime?' – '+s.endTime:''} ${sd?'· '+sd:''}</div></div>`;
        }).join(''):'<div style="color:var(--txt3);font-size:13px;">Keine Unteraufgaben</div>'}
        <div style="display:flex;gap:8px;margin-top:12px;">
          <button class="btn-secondary" style="flex:1;" onclick="openEditPlanModal('${dateStr}',${ti})">Bearbeiten</button>
          <button class="btn-danger" onclick="deleteTask('${dateStr}',${ti})">Löschen</button>
        </div>
      </div>
    `;
    cont.appendChild(card);
  });
}
window.changeDay = function(dir) {
  planningDay = new Date(planningDay.getTime()+dir*86400000);
  renderPlan();
};
window.deleteTask = function(dateStr,ti) {
  showConfirm('Aufgabe löschen?', 'Diese Aktion kann nicht rückgängig gemacht werden.', async () => {
    plans[dateStr].tasks.splice(ti,1);
    await setDoc(doc(db,'users',uid(),'plans',dateStr),plans[dateStr]);
    showToast('Aufgabe gelöscht');
    renderPlan();
  });
};

// Build Plan Modal
let tempTasks = [];
window.openAddPlanModal = function() {
  const dateStr = fmt(planningDay);
  // Keep existing tasks so new ones are appended, not replaced
  const existing = plans[dateStr]?.tasks;
  tempTasks = existing ? JSON.parse(JSON.stringify(existing)) : [];
  showPlanModal(dateStr, null);
};
window.openEditPlanModal = function(dateStr, ti) {
  tempTasks = JSON.parse(JSON.stringify(plans[dateStr].tasks));
  showPlanModal(dateStr, ti);
};

