window.saveTest = async function(subjId) {
  const name=document.getElementById('test-name').value.trim();
  const date=document.getElementById('test-date').value;
  const goal=parseFloat(document.getElementById('test-goal').value)||0;
  const taskName=document.getElementById('test-task').value.trim();
  if(!name||!date){showToast('Bitte Name und Datum eingeben');return;}
  const testId='t'+Date.now();
  const subj=subjects.find(s=>s.id===subjId);
  if(!subj) return;
  subj.tests=subj.tests||[];
  // Create calendar event for this test
  const evRef = await addDoc(userRef('events'), {title:'📝 '+name, date, time:'', testId});
  events.push({id:evRef.id, title:'📝 '+name, date, time:'', testId});
  events.sort((a,b)=>a.date.localeCompare(b.date));
  subj.tests.push({id:testId, name, date, goalHours:goal, taskName, eventId:evRef.id});
  await updateDoc(doc(db,'users',uid(),'subjects',subjId),{tests:subj.tests});
  document.getElementById('test-modal').remove();
  showToast('Prüfung hinzugefügt ✓');
  renderLearn();
};
window.deleteTest = function(subjId,testId) {
  showConfirm('Prüfung entfernen?', 'Die Prüfung wird dauerhaft gelöscht.', async () => {
    const subj=subjects.find(s=>s.id===subjId);
    if(!subj) return;
    // Remove linked calendar event
    const test = subj.tests.find(t=>t.id===testId);
    if(test?.eventId) {
      try {
        await deleteDoc(doc(db,'users',uid(),'events',test.eventId));
        events = events.filter(e=>e.id!==test.eventId);
      } catch(e) { console.warn('Event delete error:', e); }
    }
    subj.tests=subj.tests.filter(t=>t.id!==testId);
    await updateDoc(doc(db,'users',uid(),'subjects',subjId),{tests:subj.tests});
    showToast('Prüfung entfernt');
    renderLearn();
    renderCal();
  });
};

