// ── Cal Popup ─────────────────────────────────────────────────────────────
let calPopupMonth = null;
function renderCalPopup() {
  const existing = document.getElementById('cal-popup');
  if (!existing) return;
  const y = calPopupMonth.getFullYear(), mo = calPopupMonth.getMonth();
  const firstDay = new Date(y,mo,1), lastDay = new Date(y,mo+1,0);
  const todayStr = fmt(new Date());
  let startDow = (firstDay.getDay()+6)%7;
  let days = '';
  for(let i=0;i<startDow;i++) days+=`<div class="cal-day other-month"></div>`;
  for(let d=1;d<=lastDay.getDate();d++){
    const ds=`${y}-${String(mo+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const sel = ds===fmt(planningDay) ? 'selected' : '';
    const tod = ds===todayStr ? 'today' : '';
    const hasEv = events.some(e=>e.date===ds) ? 'has-event-bar' : '';
    days+=`<div class="cal-day ${sel} ${tod} ${hasEv}" onclick="popupDaySelect('${ds}')">${d}</div>`;
  }
  existing.innerHTML=`<div class="cal-popup-inner">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;">
      <button class="day-nav-btn" onclick="calPopupNav(-1)"><svg viewBox="0 0 24 24"><polyline points="15 18 9 12 15 6"/></svg></button>
      <div style="font-size:15px;font-weight:800;">${firstDay.toLocaleDateString('de-CH',{month:'long',year:'numeric'})}</div>
      <button class="day-nav-btn" onclick="calPopupNav(1)"><svg viewBox="0 0 24 24"><polyline points="9 18 15 12 9 6"/></svg></button>
    </div>
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
      <button class="btn-secondary" style="font-size:11px;padding:4px 10px;" onclick="popupDaySelect('${todayStr}')">Heute</button>
      <button class="icon-btn" onclick="document.getElementById('cal-popup').remove()"><svg viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button>
    </div>
    <div class="cal-grid">
      ${['Mo','Di','Mi','Do','Fr','Sa','So'].map(d=>`<div class="cal-day-name">${d}</div>`).join('')}
      ${days}
    </div>
  </div>`;
}
window.calPopupNav = function(dir) {
  calPopupMonth = new Date(calPopupMonth.getFullYear(), calPopupMonth.getMonth()+dir, 1);
  renderCalPopup();
};
window.openCalPopup = function() {
  const existing = document.getElementById('cal-popup');
  if(existing) { existing.remove(); return; }
  calPopupMonth = new Date(planningDay.getFullYear(), planningDay.getMonth(), 1);
  const m = document.createElement('div');
  m.className='cal-popup'; m.id='cal-popup';
  m.onclick=e=>{ if(e.target===m) m.remove(); };
  document.body.appendChild(m);
  renderCalPopup();
};
window.popupDaySelect = function(ds) {
  planningDay=parseDate(ds);
  document.getElementById('cal-popup')?.remove();
  renderPlan();
};

