function hideLoading() {
  const el = document.getElementById('loading');
  if (el) { el.style.opacity='0'; setTimeout(()=>{ el.style.display='none'; }, 500); }
}

onAuthStateChanged(auth, async user=>{
  if(user){
    currentUser = user;
    try {
      await Promise.race([
        loadAll(),
        new Promise((_,rej) => setTimeout(()=>rej(new Error('Timeout')), 12000))
      ]);
    } catch(e) {
      console.warn('loadAll error:', e);
    }
    try { await loadSettingsFromFirestore(); } catch(e) { console.warn('settings error:', e); }
    hideLoading();
    setTimeout(()=>{
      document.getElementById('auth-screen').classList.add('hidden');
      document.getElementById('app').style.display='flex';
      switchTab('home');
    }, 500);
  } else {
    currentUser = null;
    hideLoading();
    setTimeout(()=>{
      document.getElementById('auth-screen').classList.remove('hidden');
      document.getElementById('app').style.display='none';
    }, 500);
  }
});

// ── CONFIRM DIALOG (replaces browser confirm) ────────────────────────────
function showConfirm(title, msg, onConfirm) {
  // Remove any existing
  const existing = document.getElementById('confirm-modal');
  if (existing) existing.remove();

  const el = document.createElement('div');
  el.className = 'confirm-backdrop';
  el.id = 'confirm-modal';
  el.innerHTML = `
    <div class="confirm-sheet" id="confirm-sheet">
      <div class="confirm-handle" id="confirm-handle"></div>
      <div class="confirm-title">${title}</div>
      <div class="confirm-msg">${msg}</div>
      <div class="confirm-btns">
        <button class="confirm-btn-del" id="confirm-yes">Löschen</button>
        <button class="confirm-btn-cancel" id="confirm-no">Abbrechen</button>
      </div>
    </div>
  `;
  document.body.appendChild(el);

  function closeConfirm(confirmed) {
    const sheet = document.getElementById('confirm-sheet');
    if (sheet) { sheet.classList.add('exit'); }
    setTimeout(() => { el.remove(); if (confirmed) onConfirm(); }, 280);
  }

  document.getElementById('confirm-yes').onclick = () => closeConfirm(true);
  document.getElementById('confirm-no').onclick = () => closeConfirm(false);
  el.addEventListener('click', (e) => { if (e.target === el) closeConfirm(false); });

  // Swipe down to close
  attachSwipeToClose(document.getElementById('confirm-sheet'), () => closeConfirm(false));
}

// ── SWIPE TO CLOSE (attaches to any sheet element) ───────────────────────
function attachSwipeToClose(sheet, onClose) {
  if (!sheet) return;
  let startY = 0, curY = 0, dragging = false, lockedAxis = null;

  // Only attach swipe on the handle area (top 40px of sheet)
  const handle = sheet.querySelector('.modal-handle') || sheet;

  function onStart(e) {
    const t = e.touches ? e.touches[0] : e;
    startY = t.clientY; curY = 0; dragging = true; lockedAxis = null;
    sheet.classList.add('sliding');
  }
  function onMove(e) {
    if (!dragging) return;
    const t = e.touches ? e.touches[0] : e;
    const dy = t.clientY - startY;
    const dx = Math.abs(t.clientX - (e.touches ? e.touches[0].clientX : t.clientX));

    // Lock axis on first significant movement
    if (!lockedAxis) {
      if (Math.abs(dy) > 6) lockedAxis = 'y';
      else if (dx > 6) { lockedAxis = 'x'; dragging = false; return; }
      else return;
    }

    curY = dy < 0 ? 0 : dy;
    sheet.style.transform = 'translateY(' + curY + 'px)';
    // Only prevent default when dragging the sheet down (not scrolling content)
    if (curY > 0) {
      e.preventDefault();
    }
  }
  function onEnd() {
    if (!dragging) return;
    dragging = false; lockedAxis = null;
    sheet.classList.remove('sliding');
    if (curY > 100) {
      sheet.style.transform = 'translateY(100%)';
      setTimeout(onClose, 280);
    } else {
      sheet.style.transform = '';
    }
  }

  // Attach to handle only so scroll inside modal works freely
  handle.addEventListener('touchstart', onStart, { passive: true });
  sheet.addEventListener('touchmove', onMove, { passive: false });
  sheet.addEventListener('touchend', onEnd);
}

// ── ATTACH SWIPE TO ALL MODALS when they open ────────────────────────────
// Safety: if backdrop is tapped directly (not on modal), close it
document.addEventListener('touchend', (e) => {
  const backdrop = e.target?.closest?.('.modal-backdrop');
  if (backdrop && e.target === backdrop) {
    backdrop.style.transition = 'opacity .2s';
    backdrop.style.opacity = '0';
    setTimeout(() => backdrop.remove(), 200);
  }
}, { passive: true });

const _origAppendChild = Element.prototype.appendChild;
Element.prototype.appendChild = function(child) {
  const result = _origAppendChild.call(this, child);
  if (child && child.classList && child.classList.contains('modal-backdrop')) {
    const sheet = child.querySelector('.modal');
    if (sheet) {
      requestAnimationFrame(() => {
        attachSwipeToClose(sheet, () => {
          sheet.style.transform = 'translateY(100%)';
          setTimeout(() => child.remove(), 280);
        });
      });
    }
  }
  return result;
};

